  if (!subscriptions.has(workflowId) && subscriptions.size >= MAX_SUBSCRIPTIONS) {
    send(socket, makeErrorFrame('SUBSCRIPTION_LIMIT', 'Maximum 4 concurrent subscriptions'));
    socket.close(4002, 'Subscription limit exceeded');
    return;
