  const itemRows = reader
    .prepare(
      'SELECT id, stage_id, status, current_phase, retry_count, blocked_reason FROM items WHERE workflow_id = ? ORDER BY rowid',
    )
    .all(workflowId) as Array<{
      id: string;
      stage_id: string;
      status: string;
      current_phase: string | null;
      retry_count: number;
      blocked_reason: string | null;
    }>;

  const items: ItemProjection[] = itemRows.map((i) => ({
    id: i.id,
    stageId: i.stage_id,
    state: {
      status: i.status,
      currentPhase: i.current_phase,
      retryCount: i.retry_count,
      blockedReason: i.blocked_reason,
    },
    displayTitle: null,
    displaySubtitle: null,
  }));

  const sessionRows = reader
    .prepare(
      'SELECT id, phase, started_at, parent_session_id FROM sessions WHERE workflow_id = ? AND ended_at IS NULL ORDER BY started_at',
    )
    .all(workflowId) as Array<{
      id: string;
      phase: string;
      started_at: string;
      parent_session_id: string | null;
    }>;

