    workflow: {
      id: wf.id,
      name: wf.name,
      status: wf.status,
      currentStage: wf.current_stage,
      createdAt: wf.created_at,
      recoveryState: wf.recovery_state ? JSON.parse(wf.recovery_state) : null,
