573	    frames.forEach((f) => handle.state.backfillBuffer.push(sessionId, f));
574	
575	    const s = await connectWs();
576	    await s.next(); // hello
577	
578	    s.send({ v: 1, type: 'subscribe', id: 'seq-sub', payload: { workflowId: 'seq-wf2', sinceSeq: 6 } });
579	    await s.next(); // snapshot
580	
581	    const r7 = await s.next();
582	    const r8 = await s.next();
583	    const r9 = await s.next();
584	    s.close();
585	
586	    expect(r7.seq).toBe(7);
587	    expect(r8.seq).toBe(8);
588	    expect(r9.seq).toBe(9);
589	  });
590	});
