1	/**
2	 * WebSocket protocol tests — feat-fastify-ws.
3	 *
4	 * Covers:
5	 *   AC-1: hello frame + protocolVersion; close 4001 on mismatch.
6	 *   AC-2: subscribe → workflow.snapshot + backfill / backfill.truncated.
7	 *   AC-3: subscription cap (4 max; 5th → error + close 4002).
8	 *   AC-4: control commandId idempotency.
9	 *   AC-6: server binds 127.0.0.1 only.
10	 *
11	 * Uses real Fastify server + real ws.WebSocket connections.
12	 * No mocks — SQLite rows are inserted directly.
13	 *
14	 * ## WsSession (race-condition note)
15	 * The hello frame is sent by the server in the 'open' handler, which can
16	 * arrive in the SAME TCP read as the upgrade 101 response. To avoid losing
17	 * that message before nextMessage() registers its listener, WsSession
18	 * registers the 'message' handler BEFORE the 'open' event fires and stores
19	 * frames in a queue that next() drains before waiting for new arrivals.
20	 */
21	
22	import * as fs from 'fs';
23	import * as os from 'os';
24	import * as path from 'path';
25	import type { AddressInfo } from 'net';
26	import WebSocket from 'ws';
27	import { afterEach, beforeEach, describe, expect, it } from 'vitest';
28	import { createServer, type ServerHandle } from '../../src/server/api/server.js';
29	import { openDbPool } from '../../src/server/storage/db.js';
30	import { applyMigrations } from '../../src/server/storage/migrate.js';
31	import { makeFrame } from '../../src/server/api/frames.js';
32	
33	// ---------------------------------------------------------------------------
34	// Setup / teardown
35	// ---------------------------------------------------------------------------
36	
37	let tmpDir: string;
38	let db: ReturnType<typeof openDbPool>;
39	let handle: ServerHandle;
40	let wsUrl: string;
41	
42	beforeEach(async () => {
43	  tmpDir = await fs.promises.mkdtemp(path.join(os.tmpdir(), 'yoke-ws-'));
44	  db = openDbPool(path.join(tmpDir, 'test.db'));
45	
46	  const migrationsDir = new URL(
47	    '../../src/server/storage/migrations/',
48	    import.meta.url,
49	  ).pathname;
50	  await applyMigrations(db.writer, migrationsDir);
51	
52	  handle = await createServer(db);
53	  await handle.fastify.listen({ host: '127.0.0.1', port: 0 });
54	  const addr = handle.fastify.server.address() as AddressInfo;
55	  wsUrl = `ws://127.0.0.1:${addr.port}/stream`;
56	});
57	
58	afterEach(async () => {
59	  await handle.fastify.close();
60	  db.close();
61	  await fs.promises.rm(tmpDir, { recursive: true, force: true });
62	});
63	
64	// ---------------------------------------------------------------------------
65	// WsSession — buffered message queue (no race condition with hello frame)
66	// ---------------------------------------------------------------------------
67	
68	interface WsSession {
69	  /** Dequeues the next frame (buffered or awaited). */
70	  next(): Promise<Record<string, unknown>>;
71	  /** Serialises frame to JSON and sends. */
72	  send(frame: object): void;
73	  /** Sends raw string bytes (for testing malformed input). */
74	  sendRaw(data: string): void;
75	  close(): void;
76	  onClose(): Promise<{ code: number; reason: string }>;
77	}
78	
79	function connectWs(): Promise<WsSession> {
80	  return new Promise<WsSession>((resolve, reject) => {
81	    const ws = new WebSocket(wsUrl);
82	    const queue: Record<string, unknown>[] = [];
83	    const waiters: Array<[(m: Record<string, unknown>) => void, (e: Error) => void]> = [];
84	    let closed = false;
85	    const closeCallbacks: Array<(info: { code: number; reason: string }) => void> = [];
86	
87	    // Register 'message' BEFORE 'open' fires so hello is never dropped.
88	    ws.on('message', (data: Buffer | string) => {
89	      try {
90	        const msg = JSON.parse(data.toString()) as Record<string, unknown>;
91	        if (waiters.length > 0) {
92	          const [res] = waiters.shift()!;
93	          res(msg);
94	        } else {
95	          queue.push(msg);
96	        }
97	      } catch {
98	        // ignore non-JSON
99	      }
100	    });
101	
102	    ws.on('close', (code, reason) => {
103	      closed = true;
104	      const info = { code, reason: reason.toString() };
105	      for (const cb of closeCallbacks) cb(info);
106	      // Reject any pending waiters (socket closed before message).
107	      for (const [, rej] of waiters) {
108	        rej(new Error(`WS closed with code ${code} before expected message`));
109	      }
110	      waiters.length = 0;
111	    });
112	
113	    ws.once('open', () =>
114	      resolve({
115	        next: () => {
116	          if (queue.length > 0) return Promise.resolve(queue.shift()!);
117	          if (closed) return Promise.reject(new Error('WS already closed'));
118	          return new Promise<Record<string, unknown>>((res, rej) => {
119	            waiters.push([res, rej]);
120	          });
121	        },
122	        send: (frame: object) => ws.send(JSON.stringify(frame)),
123	        sendRaw: (data: string) => ws.send(data),
124	        close: () => ws.close(),
125	        onClose: () =>
126	          new Promise<{ code: number; reason: string }>((res) => {
127	            if (closed) res({ code: 0, reason: '' });
128	            else closeCallbacks.push(res);
129	          }),
130	      }),
131	    );
132	    ws.once('error', reject);
133	    ws.on('unexpected-response', (_req, res) => {
134	      reject(new Error(`Unexpected HTTP response: ${res.statusCode}`));
135	    });
136	  });
137	}
